Функция СгруппироватьТаблицу(ТаблицаЗначений, ИмяКолонкиГруппировки, ИмяЧисловойКолонки)

	СоответствиеСумм = Новый Соответствие;

	Для Каждого СтрокаТЗ Из ТаблицаЗначений Цикл
		КлючГруппировки = СтрокаТЗ[ИмяКолонкиГруппировки];
		ЗначениеСуммы = СтрокаТЗ[ИмяЧисловойКолонки];

		Если СоответствиеСумм[КлючГруппировки] = Неопределено Тогда
			СоответствиеСумм.Вставить(КлючГруппировки, ЗначениеСуммы);
		Иначе
			СоответствиеСумм[КлючГруппировки] = СоответствиеСумм[КлючГруппировки] + ЗначениеСуммы;
		КонецЕсли;
	КонецЦикла;

	Результат = Новый ТаблицаЗначений;
	Результат.Колонки.Добавить(ИмяКолонкиГруппировки);
	Результат.Колонки.Добавить("Сумма");

	Для Каждого КлючЗначение Из СоответствиеСумм Цикл
		НоваяСтрока = Результат.Добавить();
		НоваяСтрока[ИмяКолонкиГруппировки] = КлючЗначение.Ключ;
		НоваяСтрока.Сумма = КлючЗначение.Значение;
	КонецЦикла;

	Возврат Результат;

КонецФункции

Функция СгруппироватьТаблицуЗначений(Таблица, КолонкаГруппировки, КолонкаСуммирования)

	ТаблицаКопия = Таблица.Скопировать(, КолонкаГруппировки + ", " + КолонкаСуммирования);
	ТаблицаКопия.Свернуть(КолонкаГруппировки, КолонкаСуммирования);

	Результат = Новый ТаблицаЗначений;
	Результат.Колонки.Добавить("Значение", Таблица.Колонки[КолонкаГруппировки].ТипЗначения);
	Результат.Колонки.Добавить("Сумма", Таблица.Колонки[КолонкаСуммирования].ТипЗначения);

	Для Каждого СтрокаКопии Из ТаблицаКопия Цикл
		НоваяСтрока = Результат.Добавить();
		НоваяСтрока.Значение = СтрокаКопии[КолонкаГруппировки];
		НоваяСтрока.Сумма = СтрокаКопии[КолонкаСуммирования];
	КонецЦикла;

	Возврат Результат;

КонецФункции

Функция СгруппироватьТаблицуЗначений(ТаблицаИсточник, ИмяКолонкиГруппировки, ИмяКолонкиСуммы)
    Результат = Новый ТаблицаЗначений;
    Результат.Колонки.Добавить(ИмяКолонкиГруппировки);
    Результат.Колонки.Добавить(ИмяКолонкиСуммы, Новый ОписаниеТипов("Число"));

    Группировки = Новый Соответствие;

    Для Каждого СтрокаИсточника Из ТаблицаИсточник Цикл
        ЗначениеГруппировки = СтрокаИсточника[ИмяКолонкиГруппировки];
        Сумма = Группировки.Получить(ЗначениеГруппировки);
        Если Сумма = Неопределено Тогда
            Сумма = 0;
        КонецЕсли;
        Группировки.Вставить(ЗначениеГруппировки, Сумма + СтрокаИсточника[ИмяКолонкиСуммы]);
    КонецЦикла;

    Для Каждого Группировка Из Группировки Цикл
        НоваяСтрока = Результат.Добавить();
        НоваяСтрока[ИмяКолонкиГруппировки] = Группировка.Ключ;
        НоваяСтрока[ИмяКолонкиСуммы] = Группировка.Значение;
    КонецЦикла;

    Возврат Результат;
КонецФункции

Функция ГруппироватьТаблицуЗначений(ТаблицаЗначений, ИмяКолонкиГруппировки, ИмяКолонкиСуммы) Экспорт

	Результат = Новый ТаблицаЗначений;
	Результат.Колонки.Добавить("Группировка");
	Результат.Колонки.Добавить("Сумма");

	// Собираем уникальные значения группировки с помощью временной структуры
	КэшСумм = Новый Соответствие;

	Для Каждого Строка Из ТаблицаЗначений Цикл
		КлючГруппировки = Строка[ИмяКолонкиГруппировки];
		ТекущаяСумма = КэшСумм.Получить(КлючГруппировки);
		Если ТекущаяСумма = Неопределено Тогда
			ТекущаяСумма = 0;
		КонецЕсли;
		КэшСумм.Вставить(КлючГруппировки, ТекущаяСумма + Строка[ИмяКолонкиСуммы]);
	КонецЦикла;

	Для Каждого КлючЗначение Из КэшСумм Цикл
		НоваяСтрока = Результат.Добавить();
		НоваяСтрока.Группировка = КлючЗначение.Ключ;
		НоваяСтрока.Сумма = КлючЗначение.Значение;
	КонецЦикла;

	Возврат Результат;

КонецФункции

Функция СгруппироватьТаблицуЗначений(ИсходнаяТаблица, ИмяКолонкиГруппировки, ИмяКолонкиСуммирования) Экспорт

	Результат = Новый ТаблицаЗначений;
	Результат.Колонки.Добавить(ИмяКолонкиГруппировки, ИсходнаяТаблица.Колонки[ИмяКолонкиГруппировки].ТипЗначения);
	Результат.Колонки.Добавить(ИмяКолонкиСуммирования, Новый ОписаниеТипов("Число"));

	ВременнаяТаблица = ИсходнаяТаблица.Скопировать();

	ВременнаяТаблица.Свернуть(ИмяКолонкиГруппировки, ИмяКолонкиСуммирования);

	Для Каждого СтрокаВременнойТаблицы Из ВременнаяТаблица Цикл
		НоваяСтрока = Результат.Добавить();
		НоваяСтрока[ИмяКолонкиГруппировки] = СтрокаВременнойТаблицы[ИмяКолонкиГруппировки];
		НоваяСтрока[ИмяКолонкиСуммирования] = СтрокаВременнойТаблицы[ИмяКолонкиСуммирования];
	КонецЦикла;

	Возврат Результат;

КонецФункции

Функция ГруппировкаТаблицыЗначений(ТаблицаИсходная, ИмяКолонкиГруппировки, ИмяКолонкиСуммы)

    ТаблицаРезультат = Новый ТаблицаЗначений;
    ТаблицаРезультат.Колонки.Добавить(ИмяКолонкиГруппировки);
    ТаблицаРезультат.Колонки.Добавить(ИмяКолонкиСуммы);

    Для Каждого СтрокаИсходная Из ТаблицаИсходная Цикл

        ЗначениеГруппировки = СтрокаИсходная[ИмяКолонкиГруппировки];
        Сумма = СтрокаИсходная[ИмяКолонкиСуммы];

        НайденныеСтроки = ТаблицаРезультат.НайтиСтроки(Новый Структура(ИмяКолонкиГруппировки, ЗначениеГруппировки));

        Если НайденныеСтроки.Количество() > 0 Тогда
            НайденныеСтроки[0][ИмяКолонкиСуммы] = НайденныеСтроки[0][ИмяКолонкиСуммы] + Сумма;
        Иначе
            НоваяСтрока = ТаблицаРезультат.Добавить();
            НоваяСтрока[ИмяКолонкиГруппировки] = ЗначениеГруппировки;
            НоваяСтрока[ИмяКолонкиСуммы] = Сумма;
        КонецЕсли;

    КонецЦикла;

    Возврат ТаблицаРезультат;

КонецФункции

Функция ГруппировкаТаблицы(ТаблицаЗначений, ИмяКолонкиГруппировки, ИмяКолонкиСуммирования)

	НоваяТаблица = Новый ТаблицаЗначений;
	НоваяТаблица.Колонки.Добавить("Группа");
	НоваяТаблица.Колонки.Добавить("Сумма");

	Для Каждого СтрокаТЗ Из ТаблицаЗначений Цикл
		ЗначениеГруппы = СтрокаТЗ[ИмяКолонкиГруппировки];
		Найден = Ложь;
		Для Каждого СтрокаНовой Из НоваяТаблица Цикл
			Если СтрокаНовой.Группа = ЗначениеГруппы Тогда
				СтрокаНовой.Сумма = СтрокаНовой.Сумма + СтрокаТЗ[ИмяКолонкиСуммирования];
				Найден = Истина;
				Прервать;
			КонецЕсли;
		КонецЦикла;

		Если Не Найден Тогда
			НовСтр = НоваяТаблица.Добавить();
			НовСтр.Группа = ЗначениеГруппы;
			НовСтр.Сумма = СтрокаТЗ[ИмяКолонкиСуммирования];
		КонецЕсли;

	КонецЦикла;

	Возврат НоваяТаблица;

КонецФункции

Функция УникальныеЭлементыМассива(ИсходныйМассив)
    Результат = Новый Массив;
    УжеДобавлены = Новый Соответствие;
    Для Каждого Элемент Из ИсходныйМассив Цикл
        Если Элемент = Неопределено Тогда
            Если Результат.Найти(Неопределено) = Неопределено Тогда
                Результат.Добавить(Неопределено);
            КонецЕсли;
        ИначеЕсли УжеДобавлены[Элемент] = Неопределено Тогда
            Результат.Добавить(Элемент);
            УжеДобавлены.Вставить(Элемент, Истина);
        КонецЕсли;
    КонецЦикла;
    Возврат Результат;
КонецФункции

Функция ВыделитьУникальныеЭлементы(Массив)
    Результат = Новый Массив;
    Уникальные = Новый Соответствие;
    Для Каждого Элемент Из Массив Цикл
        Если Уникальные[Элемент] = Неопределено Тогда
            Уникальные[Элемент] = Истина;
            Результат.Добавить(Элемент);
        КонецЕсли;
    КонецЦикла;
    Возврат Результат;
КонецФункции

Функция ВыделитьУникальныеЭлементы(Знач Массив)

    Результат = Новый Массив;
    ВременнаяСтруктура = Новый Структура;

    Для Каждого Элемент Из Массив Цикл

        // Преобразуем элемент в допустимое имя свойства структуры
        ИмяСвойства = "_" + СтрЗаменить(СтрЗаменить(СтрЗаменить(
            XMLСтрока(Элемент), "-", "_"), ".", "_"), " ", "_");

        // Проверяем наличие ключа через попытку доступа
        Попытка
            Значение = Неопределено;
            ВременнаяСтруктура.Свойство(ИмяСвойства, Значение);
            Если Значение <> Неопределено Тогда
                // Элемент уже встречался, пропускаем
                Продолжить;
            КонецЕсли;
        Исключение
            // Ключа нет — элемент новый
        КонецПопытки;

        ВременнаяСтруктура.Вставить(ИмяСвойства, Истина);
        Результат.Добавить(Элемент);

    КонецЦикла;

    Возврат Результат;

КонецФункции

Функция ВыделитьУникальныеЭлементы(Массив)
    Результат = Новый Массив;
    Для Каждого Элемент Из Массив Цикл
        Если Результат.Найти(Элемент) = Неопределено Тогда
            Результат.Добавить(Элемент);
        КонецЕсли;
    КонецЦикла;
    Возврат Результат;
КонецФункции

Функция ОбъединитьИнтервалы(Интервалы) Экспорт

    Таблица = Новый ТаблицаЗначений;
    Таблица.Колонки.Добавить("Начало");
    Таблица.Колонки.Добавить("Конец");

    Для каждого Интервал Из Интервалы Цикл
        СтрокаТЗ = Таблица.Добавить();
        СтрокаТЗ.Начало = Интервал[0];
        СтрокаТЗ.Конец = Интервал[1];
    КонецЦикла;

    Таблица.Сортировать("Начало");

    Результат = Новый Массив;

    Для каждого СтрокаТЗ Из Таблица Цикл
        Если Результат.Количество() = 0 Тогда
            НовыйИнт = Новый Массив;
            НовыйИнт.Добавить(СтрокаТЗ.Начало);
            НовыйИнт.Добавить(СтрокаТЗ.Конец);
            Результат.Добавить(НовыйИнт);
        Иначе
            Последний = Результат[Результат.Количество() - 1];
            Если СтрокаТЗ.Начало <= Последний[1] Тогда
                Если СтрокаТЗ.Конец > Последний[1] Тогда
                    Последний[1] = СтрокаТЗ.Конец;
                КонецЕсли;
            Иначе
                НовыйИнт = Новый Массив;
                НовыйИнт.Добавить(СтрокаТЗ.Начало);
                НовыйИнт.Добавить(СтрокаТЗ.Конец);
                Результат.Добавить(НовыйИнт);
            КонецЕсли;
        КонецЕсли;
    КонецЦикла;

    Возврат Результат;

КонецФункции

Функция ОбъединитьИнтервалы(МассивИнтервалов) Экспорт

	ТЗ = Новый ТаблицаЗначений;
	ТЗ.Колонки.Добавить("Начало");
	ТЗ.Колонки.Добавить("Интервал");

	Для Каждого Интервал Из МассивИнтервалов Цикл
		СтрокаТЗ = ТЗ.Добавить();
		СтрокаТЗ.Начало = Интервал[0];
		СтрокаТЗ.Интервал = Интервал;
	КонецЦикла;

	ТЗ.Сортировать("Начало Возр");

	Результат = Новый Массив;

	Для Каждого СтрокаТЗ Из ТЗ Цикл
		ТекНачало = СтрокаТЗ.Интервал[0];
		ТекКонец = СтрокаТЗ.Интервал[1];

		Если Результат.Количество() = 0 Тогда
			НовыйИнтервал = Новый Массив;
			НовыйИнтервал.Добавить(ТекНачало);
			НовыйИнтервал.Добавить(ТекКонец);
			Результат.Добавить(НовыйИнтервал);
		Иначе
			ПоследнийИнтервал = Результат[Результат.ВГраница()];

			Если ТекНачало <= ПоследнийИнтервал[1] Тогда
				Если ТекКонец > ПоследнийИнтервал[1] Тогда
					ПоследнийИнтервал[1] = ТекКонец;
				КонецЕсли;
			Иначе
				НовыйИнтервал = Новый Массив;
				НовыйИнтервал.Добавить(ТекНачало);
				НовыйИнтервал.Добавить(ТекКонец);
				Результат.Добавить(НовыйИнтервал);
			КонецЕсли;
		КонецЕсли;
	КонецЦикла;

	Возврат Результат;

КонецФункции

Функция ОбъединитьИнтервалы(Интервалы) Экспорт

    Результат = Новый Массив;

    Если Интервалы = Неопределено Или Интервалы.Количество() = 0 Тогда
        Возврат Результат;
    КонецЕсли;

    Таб = Новый ТаблицаЗначений;
    Таб.Колонки.Добавить("Начало", Новый ОписаниеТипов("Число"));
    Таб.Колонки.Добавить("Конец", Новый ОписаниеТипов("Число"));

    Для Каждого Интервал Из Интервалы Цикл
        Если Интервал = Неопределено Или Интервал.Количество() < 2 Тогда
            Продолжить;
        КонецЕсли;
        Стр = Таб.Добавить();
        Стр.Начало = Интервал[0];
        Стр.Конец = Интервал[1];
    КонецЦикла;

    Если Таб.Количество() = 0 Тогда
        Возврат Результат;
    КонецЕсли;

    Таб.Сортировать("Начало Возр, Конец Возр");

    ТекНачало = Таб[0].Начало;
    ТекКонец = Таб[0].Конец;

    Для Инд = 1 По Таб.Количество() - 1 Цикл
        Стр = Таб[Инд];
        Если Стр.Начало <= ТекКонец Тогда
            Если Стр.Конец > ТекКонец Тогда
                ТекКонец = Стр.Конец;
            КонецЕсли;
        Иначе
            Интервал = Новый Массив;
            Интервал.Добавить(ТекНачало);
            Интервал.Добавить(ТекКонец);
            Результат.Добавить(Интервал);
            ТекНачало = Стр.Начало;
            ТекКонец = Стр.Конец;
        КонецЕсли;
    КонецЦикла;

    Интервал = Новый Массив;
    Интервал.Добавить(ТекНачало);
    Интервал.Добавить(ТекКонец);
    Результат.Добавить(Интервал);

    Возврат Результат;

КонецФункции

Функция ОбъединитьИнтервалы(Знач МассивИнтервалов) Экспорт

	ТЗ = Новый ТаблицаЗначений;
	ТЗ.Колонки.Добавить("Начало", Новый ОписаниеТипов("Число"));
	ТЗ.Колонки.Добавить("Конец",  Новый ОписаниеТипов("Число"));

	Для Каждого Интервал Из МассивИнтервалов Цикл
		Строка = ТЗ.Добавить();
		Строка.Начало = Интервал[0];
		Строка.Конец  = Интервал[1];
	КонецЦикла;

	ТЗ.Сортировать("Начало Возр");

	Результат = Новый Массив;

	Если ТЗ.Количество() = 0 Тогда
		Возврат Результат;
	КонецЕсли;

	ТекНачало = ТЗ[0].Начало;
	ТекКонец  = ТЗ[0].Конец;

	Для Индекс = 1 По ТЗ.Количество() - 1 Цикл
		Если ТЗ[Индекс].Начало <= ТекКонец Тогда
			ТекКонец = Макс(ТекКонец, ТЗ[Индекс].Конец);
		Иначе
			НовыйИнтервал = Новый Массив;
			НовыйИнтервал.Добавить(ТекНачало);
			НовыйИнтервал.Добавить(ТекКонец);
			Результат.Добавить(НовыйИнтервал);

			ТекНачало = ТЗ[Индекс].Начало;
			ТекКонец  = ТЗ[Индекс].Конец;
		КонецЕсли;
	КонецЦикла;

	НовыйИнтервал = Новый Массив;
	НовыйИнтервал.Добавить(ТекНачало);
	НовыйИнтервал.Добавить(ТекКонец);
	Результат.Добавить(НовыйИнтервал);

	Возврат Результат;

КонецФункции

Функция ОбъединитьИнтервалы(Интервалы)
    Если Интервалы = Неопределено ИЛИ Интервалы.Количество() = 0 Тогда
        Возврат Новый Массив;
    КонецЕсли;

    // Копируем интервалы, чтобы не модифицировать исходный массив
    Рабочие = Новый Массив;
    Для Каждого Интервал Из Интервалы Цикл
        Копия = Новый Массив;
        Копия.Добавить(Интервал[0]);
        Копия.Добавить(Интервал[1]);
        Рабочие.Добавить(Копия);
    КонецЦикла;

    // Сортируем по началу интервала (пузырьковая сортировка)
    Для Внешний = 0 По Рабочие.ВГраница() - 1 Цикл
        Для Внутренний = 0 По Рабочие.ВГраница() - Внешний - 1 Цикл
            Если Рабочие[Внутренний][0] > Рабочие[Внутренний + 1][0] Тогда
                Временный = Рабочие[Внутренний];
                Рабочие[Внутренний] = Рабочие[Внутренний + 1];
                Рабочие[Внутренний + 1] = Временный;
            КонецЕсли;
        КонецЦикла;
    КонецЦикла;

    // Объединяем пересекающиеся и соприкасающиеся интервалы
    Результат = Новый Массив;
    Текущий = Новый Массив;
    Текущий.Добавить(Рабочие[0][0]);
    Текущий.Добавить(Рабочие[0][1]);

    Для Сч = 1 По Рабочие.ВГраница() Цикл
        Если Рабочие[Сч][0] <= Текущий[1] Тогда
            // Пересекаются или соприкасаются — расширяем текущий интервал
            Если Рабочие[Сч][1] > Текущий[1] Тогда
                Текущий[1] = Рабочие[Сч][1];
            КонецЕсли;
        Иначе
            // Не пересекаются — сохраняем текущий и начинаем новый
            Результат.Добавить(Текущий);
            Текущий = Новый Массив;
            Текущий.Добавить(Рабочие[Сч][0]);
            Текущий.Добавить(Рабочие[Сч][1]);
        КонецЕсли;
    КонецЦикла;

    Результат.Добавить(Текущий);
    Возврат Результат;
КонецФункции

Функция СкользящиеСредние(МассивЧисел, Окно)

	Результат = Новый Массив;
	КоличествоЭлементов = МассивЧисел.Количество();

	Если Окно > КоличествоЭлементов Или Окно < 1 Тогда
		Возврат Результат;
	КонецЕсли;

	ТекущаяСумма = 0;

	Для Индекс = 0 По КоличествоЭлементов - 1 Цикл

		ТекущаяСумма = ТекущаяСумма + МассивЧисел[Индекс];

		Если Индекс >= Окно - 1 Тогда
			Результат.Добавить(ТекущаяСумма / Окно);
			ТекущаяСумма = ТекущаяСумма - МассивЧисел[Индекс - Окно + 1];
		КонецЕсли;

	КонецЦикла;

	Возврат Результат;

КонецФункции

Функция СкользящиеСредние(ИсходныйМассив, Окно)
    Результат = Новый Массив;
    Длина = ИсходныйМассив.Количество();

    Если Окно > Длина Тогда
        Возврат Результат;
    КонецЕсли;

    Для i = 0 По Длина - Окно Цикл
        Сумма = 0;
        Для j = i По i + Окно - 1 Цикл
            Сумма = Сумма + ИсходныйМассив[j];
        КонецЦикла;
        Среднее = Сумма / Окно;
        Результат.Добавить(Среднее);
    КонецЦикла;

    Возврат Результат;
КонецФункции;

Функция СкользящиеСредние(МассивЧисел, РазмерОкна) Экспорт

    Результат = Новый Массив;

    Если РазмерОкна < 1 Тогда
        Возврат Результат;
    КонецЕсли;

    КоличествоЭлементов = МассивЧисел.Количество();

    Если РазмерОкна > КоличествоЭлементов Тогда
        Возврат Результат;
    КонецЕсли;

    ТекущаяСумма = 0;

    Для Индекс = 0 По РазмерОкна - 1 Цикл
        ТекущаяСумма = ТекущаяСумма + МассивЧисел[Индекс];
    КонецЦикла;

    Результат.Добавить(ТекущаяСумма / РазмерОкна);

    Для Индекс = РазмерОкна По КоличествоЭлементов - 1 Цикл
        ТекущаяСумма = ТекущаяСумма + МассивЧисел[Индекс] - МассивЧисел[Индекс - РазмерОкна];
        Результат.Добавить(ТекущаяСумма / РазмерОкна);
    КонецЦикла;

    Возврат Результат;

КонецФункции

Функция СкользящиеСредние(МассивЧисел, РазмерОкна) Экспорт
    Результат = Новый Массив;

    ДлинаМассива = МассивЧисел.Количество();

    Если РазмерОкна > ДлинаМассива Тогда
        Возврат Результат;
    КонецЕсли;

    КоличествоОкон = ДлинаМассива - РазмерОкна + 1;

    Для Индекс = 0 По КоличествоОкон - 1 Цикл
        Сумма = 0;
        Для j = 0 По РазмерОкна - 1 Цикл
            Сумма = Сумма + МассивЧисел[Индекс + j];
        КонецЦикла;
        Результат.Добавить(Сумма / РазмерОкна);
    КонецЦикла;

    Возврат Результат;
КонецФункции

Функция СкольящиеСредние(МассивЧисел, Окно)

	Результат = Новый Массив;
	КоличествоЭлементов = МассивЧисел.Количество();

	Если Окно > КоличествоЭлементов Тогда
		Возврат Результат;
	КонецЕсли;

	КоличествоОкон = КоличествоЭлементов - Окно + 1;

	// Вычисляем сумму первого окна
	Сумма = 0;
	Для Индекс = 0 По Окно - 1 Цикл
		Сумма = Сумма + МассивЧисел[Индекс];
	КонецЦикла;

	Результат.Добавить(Сумма / Окно);

	// Скользящее окно: вычитаем уходящий элемент, добавляем входящий
	Для Индекс = 1 По КоличествоОкон - 1 Цикл
		Сумма = Сумма - МассивЧисел[Индекс - 1] + МассивЧисел[Индекс + Окно - 1];
		Результат.Добавить(Сумма / Окно);
	КонецЦикла;

	Возврат Результат;

КонецФункции

Функция СкользящееСреднее(МассивЧисел, Окно)
	Результат = Новый Массив;
	Количество = МассивЧисел.Количество();

	Если Количество < Окно ИЛИ Окно < 1 Тогда
		Возврат Результат;
	КонецЕсли;

	Сумма = 0;
	Для К = 0 По Окно - 1 Цикл
		Сумма = Сумма + МассивЧисел[К];
	КонецЦикла;
	Результат.Добавить(Сумма / Окно);

	Для С = 1 По Количество - Окно Цикл
		Сумма = Сумма - МассивЧисел[С - 1] + МассивЧисел[С + Окно - 1];
		Результат.Добавить(Сумма / Окно);
	КонецЦикла;

	Возврат Результат;
КонецФункции

Функция СкользящаяСредняя(МассивЧисел, РазмерОкна) Экспорт
    Если РазмерОкна > МассивЧисел.Количество() Тогда
        Возврат Новый Массив;
    КонецЕсли;

    Результат = Новый Массив;
    Для Индекс = 0 По МассивЧисел.Количество() - РазмерОкна Цикл
        Сумма = 0;
        Для Сч = 0 По РазмерОкна - 1 Цикл
            Сумма = Сумма + МассивЧисел[Индекс + Сч];
        КонецЦикла;
        Результат.Добавить(Сумма / РазмерОкна);
    КонецЦикла;

    Возврат Результат;
КонецФункции

Функция ВычислитьСкользящиеСредние(МассивЧисел, РазмерОкна) Экспорт

    // Проверка на пустой массив или некорректный размер окна
    Если МассивЧисел.Количество() = 0 Или РазмерОкна <= 0 Тогда
        Возврат Новый Массив;
    КонецЕсли;

    // Если окно больше длины массива, возвращаем пустой массив
    Если РазмерОкна > МассивЧисел.Количество() Тогда
        Возврат Новый Массив;
    КонецЕсли;

    Результат = Новый Массив;

    // Проходим по каждому возможному началу окна
    Для Индекс = 0 По МассивЧисел.Количество() - РазмерОкна Цикл

        Сумма = 0;

        // Суммируем элементы текущего окна
        Для Сч = 0 По РазмерОкна - 1 Цикл
            Сумма = Сумма + МассивЧисел[Индекс + Сч];
        КонецЦикла;

        // Вычисляем среднее и добавляем в результат
        Среднее = Сумма / РазмерОкна;
        Результат.Добавить(Среднее);

    КонецЦикла;

    Возврат Результат;

КонецФункции

Функция ПодсчитатьСлова(Текст) Экспорт
    Текст = НРег(Текст);
    Разделители = " .,!?:;()[]{}'""-—" + Символы.ПС + Символы.ВК + Символы.Таб;
    МассивСлов = СтрРазделить(Текст, Разделители, Ложь);
    Результат = Новый Структура;
    Для Каждого Слово Из МассивСлов Цикл
        Если Результат.Свойство(Слово) Тогда
            Результат[Слово] = Результат[Слово] + 1;
        Иначе
            Результат.Вставить(Слово, 1);
        КонецЕсли;
    КонецЦикла;
    Возврат Результат;
КонецФункции

Функция ПодсчитатьСлова(Текст) Экспорт
    Результат = Новый Структура;
    Разделители = " " + Символы.Таб + Символы.ПС + Символы.ВК + Символы.НПП + ".,!?;:""()[]{}<>/\-_=+|@#$%^&*~`«»—";
    ТекущееСлово = "";

    Для Индекс = 1 По СтрДлина(Текст) Цикл
        Символ = Сред(Текст, Индекс, 1);
        Если СтрНайти(Разделители, Символ) > 0 Тогда
            Если Не ПустаяСтрока(ТекущееСлово) Тогда
                Слово = НРег(ТекущееСлово);
                Если Результат.Свойство(Слово) Тогда
                    Результат[Слово] = Результат[Слово] + 1;
                Иначе
                    Результат.Вставить(Слово, 1);
                КонецЕсли;
                ТекущееСлово = "";
            КонецЕсли;
        Иначе
            ТекущееСлово = ТекущееСлово + Символ;
        КонецЕсли;
    КонецЦикла;

    Если Не ПустаяСтрока(ТекущееСлово) Тогда
        Слово = НРег(ТекущееСлово);
        Если Результат.Свойство(Слово) Тогда
            Результат[Слово] = Результат[Слово] + 1;
        Иначе
            Результат.Вставить(Слово, 1);
        КонецЕсли;
    КонецЕсли;

    Возврат Результат;
КонецФункции

Функция ПодсчетСлов(Текст) Экспорт
    Результат = Новый Структура;
    НижнийТекст = Нрег(Текст);

    // Удаляем знаки препинания, оставляем только буквы, цифры и пробелы
    СимволыДляУдаления = ",.;:!?()[]{}""''—–-«»/\\|@#$%^&*+=<>~`";
    Для Индекс = 1 По СтрДлина(СимволыДляУдаления) Цикл
        Символ = Сред(СимволыДляУдаления, Индекс, 1);
        НижнийТекст = СтрЗаменить(НижнийТекст, Символ, " ");
    КонецЦикла;

    // Разбиваем текст на слова по пробелам
    МассивСлов = СтрРазделить(НижнийТекст, " ");

    Для Каждого Слово Из МассивСлов Цикл
        Слово = СокрЛП(Слово);
        Если ЗначениеЗаполнено(Слово) Тогда
            Если Результат.Свойство(Слово) Тогда
                Результат[Слово] = Результат[Слово] + 1;
            Иначе
                Результат.Вставить(Слово, 1);
            КонецЕсли;
        КонецЕсли;
    КонецЦикла;

    Возврат Результат;
КонецФункции

Функция ПодсчитатьСлова(Знач Текст) Экспорт

    Результат = Новый Структура;

    // Заменяем знаки препинания на пробелы
    ЗнакиПунктуации = ",.:;!?-–—()[]{}»«""''""/\@#$%^&*+=<>|~`";
    РабочийТекст = НРег(Текст);

    Для Индекс = 1 По СтрДлина(ЗнакиПунктуации) Цикл
        Символ = Сред(ЗнакиПунктуации, Индекс, 1);
        РабочийТекст = СтрЗаменить(РабочийТекст, Символ, " ");
    КонецЦикла;

    // Разбиваем на слова по пробелам
    МассивСлов = СтрРазделить(РабочийТекст, " ", Ложь);

    // Подсчитываем вхождения
    Для Каждого Слово Из МассивСлов Цикл

        // Убираем оставшиеся пробелы по краям (на всякий случай)
        Слово = СокрЛП(Слово);
        Если Слово = "" Тогда
            Продолжить;
        КонецЕсли;

        Если Результат.Свойство(Слово) Тогда
            Результат[Слово] = Результат[Слово] + 1;
        Иначе
            Результат.Вставить(Слово, 1);
        КонецЕсли;

    КонецЦикла;

    Возврат Результат;

КонецФункции

Функция РасстояниеЛевенштейна(Строка1, Строка2)
    Длина1 = СтрДлина(Строка1);
    Длина2 = СтрДлина(Строка2);
    Матрица = Новый Массив(Длина1 + 1, Длина2 + 1);
    Для i = 0 По Длина1 Цикл
        Матрица[i][0] = i;
    КонецЦикла;
    Для j = 0 По Длина2 Цикл
        Матрица[0][j] = j;
    КонецЦикла;
    Для i = 1 По Длина1 Цикл
        Для j = 1 По Длина2 Цикл
            Симв1 = Сред(Строка1, i, 1);
            Симв2 = Сред(Строка2, j, 1);
            Если Симв1 = Симв2 Тогда
                Замена = 0;
            Иначе
                Замена = 1;
            КонецЕсли;
            Удалить = Матрица[i - 1][j] + 1;
            Вставить = Матрица[i][j - 1] + 1;
            Заменить = Матрица[i - 1][j - 1] + Замена;
            Матрица[i][j] = Мин(Удалить, Вставить, Заменить);
        КонецЦикла;
    КонецЦикла;
    Возврат Матрица[Длина1][Длина2];
КонецФункции

Функция Левенштейн(Строка1, Строка2) Экспорт

	М = СтрДлина(Строка1);
	Н = СтрДлина(Строка2);

	Если М = 0 Тогда
		Возврат Н;
	КонецЕсли;

	Если Н = 0 Тогда
		Возврат М;
	КонецЕсли;

	Матрица = Новый Массив;
	Для Инд1 = 0 По М Цикл
		СтрокаМатрицы = Новый Массив;
		Для Инд2 = 0 По Н Цикл
			Если Инд1 = 0 Тогда
				СтрокаМатрицы.Добавить(Инд2);
			ИначеЕсли Инд2 = 0 Тогда
				СтрокаМатрицы.Добавить(Инд1);
			Иначе
				СтрокаМатрицы.Добавить(0);
			КонецЕсли;
		КонецЦикла;
		Матрица.Добавить(СтрокаМатрицы);
	КонецЦикла;

	Для Инд1 = 1 По М Цикл
		Для Инд2 = 1 По Н Цикл
			Символ1 = Сред(Строка1, Инд1, 1);
			Символ2 = Сред(Строка2, Инд2, 1);

			Стоимость = ?(Символ1 = Символ2, 0, 1);

			Удаление = Матрица[Инд1 - 1][Инд2] + 1;
			Вставка = Матрица[Инд1][Инд2 - 1] + 1;
			Замена = Матрица[Инд1 - 1][Инд2 - 1] + Стоимость;

			Матрица[Инд1][Инд2] = Мин(Мин(Удаление, Вставка), Замена);
		КонецЦикла;
	КонецЦикла;

	Возврат Матрица[М][Н];

КонецФункции

Функция РасстояниеЛевенштейна(Строка1, Строка2)
    n = СтрДлина(Строка1);
    m = СтрДлина(Строка2);

    Если n = 0 Тогда
        Возврат m;
    КонецЕсли;
    Если m = 0 Тогда
        Возврат n;
    КонецЕсли;

    Предыдущий = Новый Массив;
    Текущий = Новый Массив;

    // инициализация первой строки таблицы
    Для j = 0 По m Цикл
        Предыдущий.Добавить(j);
    КонецЦикла;

    Для i = 1 По n Цикл
        Текущий.Очистить();
        Текущий.Добавить(i); // первая колонка текущей строки

        Для j = 1 По m Цикл
            Если Сред(Строка1, i, 1) = Сред(Строка2, j, 1) Тогда
                cost = 0;
            Иначе
                cost = 1;
            КонецЕсли;

            del = Предыдущий[j] + 1;
            ins = Текущий[j - 1] + 1;
            sub = Предыдущий[j - 1] + cost;

            min = del;
            Если ins < min Тогда min = ins; КонецЕсли;
            Если sub < min Тогда min = sub; КонецЕсли;

            Текущий.Добавить(min);
        КонецЦикла;

        // меняем ссылки массивов
        Временный = Предыдущий;
        Предыдущий = Текущий;
        Текущий = Временный;
    КонецЦикла;

    Возврат Предыдущий[m];
КонецФункции

Функция РасстояниеЛевенштейна(Строка1, Строка2)
    Длина1 = СтрДлина(Строка1);
    Длина2 = СтрДлина(Строка2);

    Если Длина1 = 0 Тогда
        Возврат Длина2;
    КонецЕсли;

    Если Длина2 = 0 Тогда
        Возврат Длина1;
    КонецЕсли;

    Предыдущая = Новый Массив(Длина2 + 1);
    Текущая    = Новый Массив(Длина2 + 1);

    Для j = 0 По Длина2 Цикл
        Предыдущая[j] = j;
    КонецЦикла;

    Для i = 1 По Длина1 Цикл
        Текущая[0] = i;
        Символ1 = Сред(Строка1, i, 1);

        Для j = 1 По Длина2 Цикл
            Символ2 = Сред(Строка2, j, 1);
            СтоимостьЗамены = ?(Символ1 = Символ2, 0, 1);

            Удаление = Предыдущая[j] + 1;
            Вставка  = Текущая[j - 1] + 1;
            Замена   = Предыдущая[j - 1] + СтоимостьЗамены;

            Текущая[j] = Мин(Удаление, Мин(Вставка, Замена));
        КонецЦикла;

        Временная = Предыдущая;
        Предыдущая = Текущая;
        Текущая = Временная;
    КонецЦикла;

    Возврат Предыдущая[Длина2];
КонецФункции

Функция РедакционноеРасстояние(Строка1, Строка2) Экспорт
    ДлинаСтроки1 = СтрДлина(Строка1);
    ДлинаСтроки2 = СтрДлина(Строка2);

    // Создаем двумерный массив (матрицу)
    Матрица = Новый Массив(ДлинаСтроки1 + 1);
    Для i = 0 По ДлинаСтроки1 Цикл
        Матрица[i] = Новый Массив(ДлинаСтроки2 + 1);
        Для j = 0 По ДлинаСтроки2 Цикл
            Матрица[i][j] = 0;
        КонецЦикла;
    КонецЦикла;

    // Инициализация первой строки и первого столбца
    Для i = 0 По ДлинаСтроки1 Цикл
        Матрица[i][0] = i;
    КонецЦикла;
    Для j = 0 По ДлинаСтроки2 Цикл
        Матрица[0][j] = j;
    КонецЦикла;

    // Заполнение матрицы
    Для i = 1 По ДлинаСтроки1 Цикл
        Для j = 1 По ДлинаСтроки2 Цикл
            Стоимость = ?(Сред(Строка1, i, 1) = Сред(Строка2, j, 1), 0, 1);

            Матрица[i][j] = Мин(
                Матрица[i - 1][j] + 1,       // удаление
                Матрица[i][j - 1] + 1,       // вставка
                Матрица[i - 1][j - 1] + Стоимость  // замена
            );
        КонецЦикла;
    КонецЦикла;

    Возврат Матрица[ДлинаСтроки1][ДлинаСтроки2];
КонецФункции

Функция РасстояниеЛевенштейна(Строка1, Строка2)

    ДлинаСтроки1 = СтрДлина(Строка1);
    ДлинаСтроки2 = СтрДлина(Строка2);

    // Создание матрицы (ДлинаСтроки1+1) x (ДлинаСтроки2+1)
    Матрица = Новый Массив(ДлинаСтроки1 + 1);
    Для Индекс1 = 0 По ДлинаСтроки1 Цикл
        Матрица[Индекс1] = Новый Массив(ДлинаСтроки2 + 1);
        Матрица[Индекс1][0] = Индекс1;
    КонецЦикла;
    Для Индекс2 = 0 По ДлинаСтроки2 Цикл
        Матрица[0][Индекс2] = Индекс2;
    КонецЦикла;

    // Заполнение матрицы
    Для Индекс1 = 1 По ДлинаСтроки1 Цикл
        Символ1 = Сред(Строка1, Индекс1, 1);
        Для Индекс2 = 1 По ДлинаСтроки2 Цикл
            Символ2 = Сред(Строка2, Индекс2, 1);
            Если Символ1 = Символ2 Тогда
                Стоимость = 0;
            Иначе
                Стоимость = 1;
            КонецЕсли;

            Матрица[Индекс1][Индекс2] = Мин(
                Матрица[Индекс1 - 1][Индекс2] + 1,       // удаление
                Матрица[Индекс1][Индекс2 - 1] + 1,       // вставка
                Матрица[Индекс1 - 1][Индекс2 - 1] + Стоимость // замена или совпадение
            );
        КонецЦикла;
    КонецЦикла;

    Возврат Матрица[ДлинаСтроки1][ДлинаСтроки2];

КонецФункции

Функция РасстояниеЛевенштейна(Строка1, Строка2)

    Длина1 = СтрДлина(Строка1);
    Длина2 = СтрДлина(Строка2);

    Если Длина1 = 0 Тогда
        Возврат Длина2;
    КонецЕсли;

    Если Длина2 = 0 Тогда
        Возврат Длина1;
    КонецЕсли;

    М = Новый Массив(Длина1 + 1, Длина2 + 1);

    Для Индекс1 = 0 По Длина1 Цикл
        М[Индекс1][0] = Индекс1;
    КонецЦикла;

    Для Индекс2 = 0 По Длина2 Цикл
        М[0][Индекс2] = Индекс2;
    КонецЦикла;

    Для Индекс1 = 1 По Длина1 Цикл
        Для Индекс2 = 1 По Длина2 Цикл
            Символ1 = Сред(Строка1, Индекс1, 1);
            Символ2 = Сред(Строка2, Индекс2, 1);

            Если Символ1 = Символ2 Тогда
                СтоимостьЗамены = 0;
            Иначе
                СтоимостьЗамены = 1;
            КонецЕсли;

            Удаление = М[Индекс1 - 1][Индекс2] + 1;
            Вставка = М[Индекс1][Индекс2 - 1] + 1;
            Замена = М[Индекс1 - 1][Индекс2 - 1] + СтоимостьЗамены;

            М[Индекс1][Индекс2] = Мин(Мин(Удаление, Вставка), Замена);
        КонецЦикла;
    КонецЦикла;

    Возврат М[Длина1][Длина2];

КонецФункции

Функция Левенштейн(Стр1, Стр2)

    // Оптимизация: меняем строки местами, чтобы меньшая строка была по вертикали (по столбцам)
    // Это уменьшает потребление памяти.
    Если СтрДлина(Стр1) < СтрДлина(Стр2) Тогда
        Возврат Левенштейн(Стр2, Стр1);
    КонецЕсли;

    // Инициализация предыдущей строки (расстояние от пустой строки к префиксам Стр2)
    // D[0][j] = j
    ПредыдущаяСтрока = Новый Массив;
    Для к = 0 По СтрДлина(Стр2) Цикл
        ПредыдущаяСтрока.Добавить(к);
    КонецЦикла;

    // Перебор символов первой строки
    Для i = 1 По СтрДлина(Стр1) Цикл
        // Инициализация текущей строки
        // D[i][0] = i
        ТекущаяСтрока = Новый Массив;
        ТекущаяСтрока.Добавить(i);

        Для j = 1 По СтрДлина(Стр2) Цикл
            // Стоимость замены: 0, если символы совпадают, иначе 1
            Если Сред(Стр1, i, 1) = Сред(Стр2, j, 1) Тогда
                Стоимость = 0;
            Иначе
                Стоимость = 1;
            КонецЕсли;

            // Вычисление минимума из трех операций:
            // 1. Удаление (ПредыдущаяСтрока[j] + 1)
            // 2. Вставка (ТекущаяСтрока[j-1] + 1)
            // 3. Замена (ПредыдущаяСтрока[j-1] + Стоимость)
            ТекущаяСтрока.Добавить(Мин(
                ПредыдущаяСтрока[j] + 1,
                ТекущаяСтрока[j-1] + 1,
                ПредыдущаяСтрока[j-1] + Стоимость
            ));
        КонецЦикла;

        // Переход к следующей итерации
        ПредыдущаяСтрока = ТекущаяСтрока;
    КонецЦикла;

    // Результат находится в последней ячейке матрицы
    Возврат ПредыдущаяСтрока[СтрДлина(Стр2)];

КонецФункции

