Функция СтрокиАнаграммы(Строка1, Строка2)

	С1 = СтрЗаменить(НРег(Строка1), " ", "");
	С2 = СтрЗаменить(НРег(Строка2), " ", "");

	Если СтрДлина(С1) <> СтрДлина(С2) Тогда
		Возврат Ложь;
	КонецЕсли;

	Карта = Новый Соответствие;

	Для Индекс = 1 По СтрДлина(С1) Цикл
		Символ = Сред(С1, Индекс, 1);
		Карта[Символ] = ?(Карта[Символ] = Неопределено, 1, Карта[Символ] + 1);
	КонецЦикла;

	Для Индекс = 1 По СтрДлина(С2) Цикл
		Символ = Сред(С2, Индекс, 1);
		Если Карта[Символ] = Неопределено Тогда
			Возврат Ложь;
		КонецЕсли;
		Карта[Символ] = Карта[Символ] - 1;
		Если Карта[Символ] = 0 Тогда
			Карта.Удалить(Символ);
		КонецЕсли;
	КонецЦикла;

	Возврат Карта.Количество() = 0;

КонецФункции

Функция ЭтоАнаграмма(Знач Строка1, Знач Строка2)

    С1 = ВРег(СокрЛП(Строка1));
    С1 = СтрЗаменить(С1, " ", "");

    С2 = ВРег(СокрЛП(Строка2));
    С2 = СтрЗаменить(С2, " ", "");

    Если СтрДлина(С1) <> СтрДлина(С2) Тогда
        Возврат Ложь;
    КонецЕсли;

    Для Инд = 1 По СтрДлина(С1) Цикл
        Символ = Сред(С1, Инд, 1);
        Позиция = Найти(С2, Символ);
        Если Позиция = 0 Тогда
            Возврат Ложь;
        КонецЕсли;
        С2 = Лев(С2, Позиция - 1) + Сред(С2, Позиция + 1);
    КонецЦикла;

    Возврат Истина;

КонецФункции

Функция ПростыеЧислаРешетоЭратосфена(Граница)
    Результат = Новый Массив;
    Если Граница < 2 Тогда
        Возврат Результат;
    КонецЕсли;

    Решето = Новый Массив;
    Для Индекс = 0 По Граница Цикл
        Решето.Добавить(Истина);
    КонецЦикла;
    Решето[0] = Ложь;
    Решето[1] = Ложь;

    Для Индекс = 2 По Цел(Sqrt(Граница)) Цикл
        Если Решето[Индекс] Тогда
            Кратное = Индекс * Индекс;
            Пока Кратное <= Граница Цикл
                Решето[Кратное] = Ложь;
                Кратное = Кратное + Индекс;
            КонецЦикла;
        КонецЕсли;
    КонецЦикла;

    Для Индекс = 2 По Граница Цикл
        Если Решето[Индекс] Тогда
            Результат.Добавить(Индекс);
        КонецЕсли;
    КонецЦикла;

    Возврат Результат;
КонецФункции

Функция РешетоЭратосфена(Граница)

    Результат = Новый Массив;

    Если Граница < 2 Тогда
        Возврат Результат;
    КонецЕсли;

    // Создаём массив булевых значений: Истина — число простое
    Композитные = Новый Массив(Граница + 1);
    Для Индекс = 0 По Граница Цикл
        Композитные[Индекс] = Ложь;
    КонецЦикла;

    // Алгоритм решета Эратосфена
    Делитель = 2;
    Пока Делитель * Делитель <= Граница Цикл
        Если Не Композитные[Делитель] Тогда
            Кратное = Делитель * Делитель;
            Пока Кратное <= Граница Цикл
                Композитные[Кратное] = Истина;
                Кратное = Кратное + Делитель;
            КонецЦикла;
        КонецЕсли;
        Делитель = Делитель + 1;
    КонецЦикла;

    // Собираем простые числа в результат
    Для Индекс = 2 По Граница Цикл
        Если Не Композитные[Индекс] Тогда
            Результат.Добавить(Индекс);
        КонецЕсли;
    КонецЦикла;

    Возврат Результат;

КонецФункции

