            СтрокаТЧ.Цена = 0;
            СтрокаТЧ.Сумма = 0;
        Иначе
            СтрокаТЧ.Цена = Цена;
            СтрокаТЧ.Сумма = СтрокаТЧ.Количество * СтрокаТЧ.Цена;
        КонецЕсли;
    КонецЦикла;

