Функция СписатьТоварыFIFO(ТаблицаТоваров, Склад) Экспорт

    Результат = Новый ТаблицаЗначений;
    Результат.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
    Результат.Колонки.Добавить("Партия",       Новый ОписаниеТипов("ДокументСсылка.ПоступлениеТоваров"));
    Результат.Колонки.Добавить("Количество",   Новый ОписаниеТипов("Число", Новый КвалификаторыЧисла(15, 3)));
    Результат.Колонки.Добавить("Стоимость",    Новый ОписаниеТипов("Число", Новый КвалификаторыЧисла(15, 2)));

    Требуется = Новый Соответствие;
    Для Каждого СтрокаТовара Из ТаблицаТоваров Цикл
        ТекущееКоличество = Требуется[СтрокаТовара.Номенклатура];
        Если ТекущееКоличество = Неопределено Тогда
            ТекущееКоличество = 0;
        КонецЕсли;
        Требуется[СтрокаТовара.Номенклатура] = ТекущееКоличество + СтрокаТовара.Количество;
    КонецЦикла;

    СписокНоменклатуры = ТаблицаТоваров.ВыгрузитьКолонку("Номенклатура");

    Запрос = Новый Запрос;
    Запрос.Текст =
    "ВЫБРАТЬ
    |   ПартииТоваровНаСкладахОстатки.Номенклатура КАК Номенклатура,
    |   ПартииТоваровНаСкладахОстатки.Партия КАК Партия,
    |   ПартииТоваровНаСкладахОстатки.КоличествоОстаток КАК Количество,
    |   ПартииТоваровНаСкладахОстатки.СтоимостьОстаток КАК Стоимость
    |ИЗ
    |   РегистрНакопления.ПартииТоваровНаСкладах.Остатки(, Склад = &Склад
    |       И Номенклатура В (&СписокНоменклатуры)) КАК ПартииТоваровНаСкладахОстатки
    |ГДЕ
    |   ПартииТоваровНаСкладахОстатки.КоличествоОстаток > 0
    |
    |УПОРЯДОЧИТЬ ПО
    |   ПартииТоваровНаСкладахОстатки.Партия.Дата,
    |   ПартииТоваровНаСкладахОстатки.Партия";

    Запрос.УстановитьПараметр("Склад", Склад);
    Запрос.УстановитьПараметр("СписокНоменклатуры", СписокНоменклатуры);

    Выборка = Запрос.Выполнить().Выбрать();

    Пока Выборка.Следующий() Цикл
        ОсталосьСписать = Требуется[Выборка.Номенклатура];
        Если ОсталосьСписать = Неопределено Или ОсталосьСписать <= 0 Тогда
            Продолжить;
        КонецЕсли;

        СписатьКоличество = Мин(ОсталосьСписать, Выборка.Количество);
        Если СписатьКоличество <= 0 Тогда
            Продолжить;
        КонецЕсли;

        НоваяСтрока = Результат.Добавить();
        НоваяСтрока.Номенклатура = Выборка.Номенклатура;
        НоваяСтрока.Партия       = Выборка.Партия;
        НоваяСтрока.Количество   = СписатьКоличество;

        Если Выборка.Количество <> 0 Тогда
            НоваяСтрока.Стоимость = Окр(СписатьКоличество * Выборка.Стоимость / Выборка.Количество, 2);
        Иначе
            НоваяСтрока.Стоимость = 0;
        КонецЕсли;

        Требуется[Выборка.Номенклатура] = ОсталосьСписать - СписатьКоличество;
    КонецЦикла;

    Для Каждого КлючИЗначение Из Требуется Цикл
        Если КлючИЗначение.Значение > 0 Тогда
            ВызватьИсключение "Недостаточно остатков по номенклатуре: " + КлючИЗначение.Ключ.Наименование;
        КонецЕсли;
    КонецЦикла;

    Возврат Результат;

