Функция СписатьТоварыFIFO(ТаблицаСписания, Склад) Экспорт

    Результат = Новый ТаблицаЗначений;
    Результат.Колонки.Добавить("Номенклатура");
    Результат.Колонки.Добавить("Партия");
    Результат.Колонки.Добавить("Количество");
    Результат.Колонки.Добавить("Стоимость");

    Для Каждого СтрокаСписания Из ТаблицаСписания Цикл

        Номенклатура = СтрокаСписания.Номенклатура;
        НужноСписать = СтрокаСписания.Количество;

        Запрос = Новый Запрос;
        Запрос.Текст = 
        "ВЫБРАТЬ
        |   Остатки.Партия,
        |   Остатки.КоличествоОстаток КАК Количество,
        |   Остатки.СтоимостьОстаток КАК Стоимость
        |ИЗ
        |   РегистрНакопления.ПартииТоваровНаСкладах.Остатки(
        |       ,
        |       Склад = &Склад
        |           И Номенклатура = &Номенклатура) КАК Остатки
        |ГДЕ
        |   Остатки.КоличествоОстаток > 0
        |
        |УПОРЯДОЧИТЬ ПО
        |   Остатки.Партия.Дата";

        Запрос.УстановитьПараметр("Склад", Склад);
        Запрос.УстановитьПараметр("Номенклатура", Номенклатура);

        Выборка = Запрос.Выполнить().Выбрать();

        Пока НужноСписать > 0 Цикл
            Если НЕ Выборка.Следующий() Тогда
                ВызватьИсключение "Недостаточно остатков на складе для номенклатуры: " + Строка(Номенклатура);
            КонецЕсли;

            СписатьИзПартии = Мин(НужноСписать, Выборка.Количество);

            Если Выборка.Количество > 0 Тогда
                ЦенаПартии = Выборка.Стоимость / Выборка.Количество;
                СтоимостьСписания = ЦенаПартии * СписатьИзПартии;
            Иначе
                СтоимостьСписания = 0;
            КонецЕсли;

            НоваяСтрока = Результат.Добавить();
            НоваяСтрока.Номенклатура = Номенклатура;
            НоваяСтрока.Партия = Выборка.Партия;
            НоваяСтрока.Количество = СписатьИзПартии;
            НоваяСтрока.Стоимость = СтоимостьСписания;

            НужноСписать = НужноСписать - СписатьИзПартии;
        КонецЦикла;

    КонецЦикла;

    Возврат Результат;

