Функция ABCКлассификация(НачалоПериода, КонецПериода) Экспорт

	Запрос = Новый Запрос;
	Запрос.Текст = 
		"ВЫБРАТЬ
		|	ПродажиОбороты.Номенклатура КАК Номенклатура,
		|	ПродажиОбороты.СуммаОборот КАК Сумма
		|ИЗ
		|	РегистрНакопления.Продажи.Обороты(&НачалоПериода, &КонецПериода, , ) КАК ПродажиОбороты
		|УПОРЯДОЧИТЬ ПО
		|	Сумма УБЫВ";

	Запрос.УстановитьПараметр("НачалоПериода", НачалоПериода);
	Запрос.УстановитьПараметр("КонецПериода", КонецПериода);

	Выборка = Запрос.Выполнить().Выбрать();

	ЗапросИтог = Новый Запрос;
	ЗапросИтог.Текст = 
		"ВЫБРАТЬ
		|	СУММА(ПродажиОбороты.СуммаОборот) КАК ИтогоСумма
		|ИЗ
		|	РегистрНакопления.Продажи.Обороты(&НачалоПериода, &КонецПериода, , ) КАК ПродажиОбороты";

	ЗапросИтог.УстановитьПараметр("НачалоПериода", НачалоПериода);
	ЗапросИтог.УстановитьПараметр("КонецПериода", КонецПериода);

	ИтогоСумма = ЗапросИтог.Выполнить().Выгрузить()[0].ИтогоСумма;

	ТаблицаРезультат = Новый ТаблицаЗначений;
	ТаблицаРезультат.Колонки.Добавить("Номенклатура");
	ТаблицаРезультат.Колонки.Добавить("Класс");

	Если ИтогоСумма = 0 Тогда
		Возврат ТаблицаРезультат;
	КонецЕсли;

	НакопленнаяСумма = 0;

	Пока Выборка.Следующий() Цикл
		НакопленнаяСумма = НакопленнаяСумма + Выборка.Сумма;
		Доля = НакопленнаяСумма / ИтогоСумма * 100;

		Класс = "C";
		Если Доля <= 80 Тогда
			Класс = "A";
		ИначеЕсли Доля <= 95 Тогда
			Класс = "B";
		КонецЕсли;

		СтрокаТЗ = ТаблицаРезультат.Добавить();
		СтрокаТЗ.Номенклатура = Выборка.Номенклатура;
		СтрокаТЗ.Класс = Класс;
	КонецЦикла;

	Возврат ТаблицаРезультат;

