Функция ABCКлассификация(НачалоПериода, КонецПериода) Экспорт

	Запрос = Новый Запрос;
	Запрос.Текст =
	"ВЫБРАТЬ
	|	ПродажиОбороты.Номенклатура КАК Номенклатура,
	|	ПродажиОбороты.СуммаОборот КАК Сумма
	|ИЗ
	|	РегистрНакопления.Продажи.Обороты(
	|			&НачалоПериода,
	|			&КонецПериода,
	|			,
	|			) КАК ПродажиОбороты
	|УПОРЯДОЧИТЬ ПО
	|	Сумма УБЫВ";

	Запрос.УстановитьПараметр("НачалоПериода", НачалоПериода);
	Запрос.УстановитьПараметр("КонецПериода", КонецПериода);

	Выборка = Запрос.Выполнить().Выбрать();

	МассивДанных = Новый Массив;
	ОбщаяСумма = 0;

	Пока Выборка.Следующий() Цикл
		МассивДанных.Добавить(Новый Структура("Номенклатура, Сумма",
			Выборка.Номенклатура, Выборка.Сумма));
		ОбщаяСумма = ОбщаяСумма + Выборка.Сумма;
	КонецЦикла;

	ТаблицаРезультат = Новый ТаблицаЗначений;
	ТаблицаРезультат.Колонки.Добавить("Номенклатура",
		Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
	ТаблицаРезультат.Колонки.Добавить("Класс",
		Новый ОписаниеТипов("Строка", , Новый КвалификаторыСтроки(1)));

	Если ОбщаяСумма = 0 Тогда
		Возврат ТаблицаРезультат;
	КонецЕсли;

	НакопленнаяДоля = 0;

	Для Каждого Элемент Из МассивДанных Цикл
		НакопленнаяДоля = НакопленнаяДоля + Элемент.Сумма / ОбщаяСумма * 100;

		Если НакопленнаяДоля <= 80 Тогда
			Класс = "A";
		ИначеЕсли НакопленнаяДоля <= 95 Тогда
			Класс = "B";
		Иначе
			Класс = "C";
		КонецЕсли;

		НоваяСтрока = ТаблицаРезультат.Добавить();
		НоваяСтрока.Номенклатура = Элемент.Номенклатура;
		НоваяСтрока.Класс = Класс;
	КонецЦикла;

	Возврат ТаблицаРезультат;

